namespace sttSav
{
  void splitBucket::appendOrInsert (STTSAV_VECTOR <splitBucket> & buckets, uint32_t const _value, uint32_t const _bytes)
                                                                                                                      {
		for (splitBucket& b : buckets) {
			if (b.value == _value) {
				b.bytes += _bytes;
				return;
				}
			}
		buckets.push_back(splitBucket(_value, _bytes));
		}
}
